{
  "contextId": "SEC-K8S-CTX-002-unknown-minimal-nossh",
  "environmentFingerprint": {
    "osType": "linux",
    "osFlavors": ["unknown", "minimal"],
    "shellType": "sh",
    "requiredTools": [],
    "optionalTools": [],
    "minKernelVersion": "0.0",
    "arch": ["amd64", "arm64", "arm"]
  },
  "envCheckCommands": [
    "uname -s 2>/dev/null",
    "cat /proc/1/mounts 2>/dev/null | head -1",
    "echo \"Shell: $0\""
  ],
  "executionLogic": {
    "expectedBehavior": "在安全的容器环境中，/proc/1/mounts 不应包含宿主机的敏感文件系统挂载（如/proc、/sys、/etc/kubernetes、Docker socket及根文件系统挂载点），且不应存在docker.sock文件。若存在，则意味着容器可能被用于容器逃逸或数据泄露。",
    "detectionCommands": [
      "while IFS= read -r line; do case \"$line\" in *\" /proc \"*|*\" /sys \"*|*\" /etc/kubernetes \"*|*\" /var/lib/kubelet \"*|*\" /var/run/docker.sock \"*|*\" /run/docker.sock \"*|*\" /host \"*|*\" /rootfs \"*) echo \"SENSITIVE_MOUNT_DETECTED: $line\" ;; esac; done < /proc/1/mounts 2>/dev/null || echo \"Failed to read /proc/1/mounts\"",
      "if [ -S /var/run/docker.sock ] || [ -S /run/docker.sock ]; then echo 'WARNING: docker.sock found'; fi",
      "case \"$(ls -ld /proc/1/root 2>/dev/null)\" in *\"-> /\"*|\"*-> / \"*) echo 'Possible rootfs escape via /proc/1/root' ;; esac"
    ]
  },
  "rationale": "该上下文针对无SSH服务、工具极简的未知Linux容器环境设计。通过读取 /proc/1/mounts 内核接口获取挂载信息，并结合 while read + case 实现纯 sh 内建命令的字符串匹配，避免依赖外部工具（如 grep）。检测 docker.sock 使用 test -S 内建命令，/proc/1/root 符号链接逃逸检查使用 ls -ld 与 case 匹配。envCheckCommands 通过 uname -s 确认 Linux 类型，cat /proc/1/mounts 验证 procfs 可读性，echo $0 记录 Shell 类型。整体方案等价于原有检测目标，在限制环境中仍能有效发现敏感挂载与文件系统滥用风险。"
}

