rawResponse:
{
  "contextId": "SEC-K8S-CTX-002-unknown-bare-sh",
  "environmentFingerprint": {
    "osType": "linux",
    "osFlavors": ["unknown"],
    "shellType": "sh",
    "requiredTools": ["sh", "test", "ls"],
    "optionalTools": [],
    "minKernelVersion": "0.0.0",
    "arch": ["amd64", "arm64"]
  },
  "envCheckCommands": [
    "if [ -r /proc/1/mounts ]; then echo 'HAS_PROC_MOUNTS'; else echo 'NO_PROC_MOUNTS'; fi",
    "echo SHELL=${0:-unknown}"
  ],
  "executionLogic": {
    "expectedBehavior": "在安全的容器中执行检测命令不应产生任何告警输出；如果存在 /proc、/sys、/etc/kubernetes、/var/lib/kubelet、docker socket 或 /host、/rootfs 等敏感挂载，则会输出 'SENSITIVE_MOUNT_DETECTED' 行；若发现 /var/run/docker.sock 或 /run/docker.sock，则输出 'WARNING: docker.sock found'；若 /proc/1/root 链接指向宿主根目录，则输出 'Possible rootfs escape'。",
    "detectionCommands": [
      "while IFS= read -r line; do case \"$line\" in *\" /proc \"*|*\" /sys \"*|*\" /etc/kubernetes \"*|*\" /var/lib/kubelet \"*|*\" /var/run/docker.sock \"*|*\" /run/docker.sock \"*|*\" /host \"*|*\" /rootfs \"*) echo \"SENSITIVE_MOUNT_DETECTED: $line\" ;; esac; done < /proc/1/mounts 2>/dev/null || echo \"Failed to read /proc/1/mounts\"",
      "if [ -S /var/run/docker.sock ] || [ -S /run/docker.sock ]; then echo 'WARNING: docker.sock found'; fi",
      "root_link=$(ls -l /proc/1/root 2>/dev/null); case \"$root_link\" in *\" -> /\"*|*\" -> / \"*) echo 'Possible rootfs escape via /proc/1/root' ;; esac"
    ]
  },
  "rationale": "目标环境完全未知且无法通过 SSH 连接，因此假设容器内部为极简 Linux 环境，仅有基础 POSIX shell 和 procfs。检测逻辑完全基于 shell 内建命令（read、case、test）和基础工具 sh、test、ls，无需 grep、mount 等外部程序。通过逐行分析 /proc/1/mounts 识别敏感挂载点，利用 test -S 检测 Docker socket 文件，并通过 ls -l 检查 /proc/1/root 符号链接是否指向宿主机根目录，从而等价实现原有检测目标。"
}

